/**
 * Entity Evidence Record — DATA MODEL v2 §1.1
 *
 * Canonical per-entity scoring record. One file per entity.
 *
 * Canonical source:  site/src/data/entity-records/<slug>.json
 * Derived published: public/data/records/<slug>.json  (emitted at build time by
 *   export-public-data.mjs; regenerated on every build — NOT canonical)
 *
 * Generated by: site/scripts/build-entity-records.mjs
 * Architecture:  docs/ARCHITECTURE_SUBDIMENSIONS.md
 * Data model:    docs/DATA_MODEL_SUBDIMENSIONS.md §1.1
 *
 * BUNDLE RULE: records must NEVER be statically imported en masse into the
 * client bundle. Read at build time by scripts only, or fetched one-at-a-time
 * as public/data/records/<slug>.json. (ARCHITECTURE §3.4)
 */

// ── Evidence item ──────────────────────────────────────────────────────────────

export interface EvidenceItem {
  /**
   * Evidence tier (1–5 hierarchy; 5 = strongest / primary source).
   * 1 = anecdotal / unverified; 2 = media secondary; 3 = organisational disclosure;
   * 4 = independent secondary; 5 = independent audit / regulatory finding.
   */
  tier: 1 | 2 | 3 | 4 | 5;
  /** Source URL. Empty string when the URL is not available at backfill time. */
  url: string;
  /** YYYY-MM-DD date of the evidence item. */
  date: string;
  /** Verbatim or near-verbatim supporting snippet from the source. */
  quote: string;
}

// ── Subdimension record ────────────────────────────────────────────────────────

export type SubdimSource = "assessed" | "reconstructed";

export interface SubdimensionRecord {
  /**
   * Subdimension code from dimensions.ts (e.g. "A1", "E2", "AC3", "EQ4", "AB1").
   * The 40 valid codes are: A1–A5, E1–E5, AC1–AC5, EQ1–EQ5, B1–B5, AB1–AB5,
   * S1–S5, I1–I5.
   */
  code: string;
  /** Parent dimension code (one of the 8 DimensionCode values). */
  dimension: DimensionCode;
  /** Subdimension name from dimensions.ts (must match verbatim). */
  name: string;
  /**
   * Continuous score in [1.0, 5.0], stored to 2 decimal places.
   * Exactly 0 is valid ONLY when the parent dimension's index score is 0
   * (harm floor designation). See DATA_MODEL §1.2 field rules.
   */
  score: number;
  confidence: "high" | "medium" | "low";
  /**
   * YYYY-MM-DD date the subdimension was assessed by the assessor.
   * Null when subdims_source === 'reconstructed'.
   */
  assessed_date: string | null;
  /**
   * 'assessed': real score parsed from a research/assessments/<slug>.md
   *   Dimension Details table, AND round(mean_of_5, 2) == index.scores[dimension].
   * 'reconstructed': no usable assessment for this dimension; all five subdim
   *   scores are set equal to the published dimension value so mean is exact.
   *   Represents "dimension-only, subdimension breakdown unknown."
   */
  subdims_source: SubdimSource;
  /**
   * Evidence items supporting this subdimension score.
   * Non-empty only for 'assessed' subdims; empty array for 'reconstructed'.
   */
  evidence: EvidenceItem[];
}

// ── Dimension code union ───────────────────────────────────────────────────────

/** The 8 dimension codes in canonical order (matches DIMENSION_CODES in scoring.mjs). */
export type DimensionCode =
  | "AWR"
  | "EMP"
  | "ACT"
  | "EQU"
  | "BND"
  | "ACC"
  | "SYS"
  | "INT";

// ── Entity record ──────────────────────────────────────────────────────────────

export interface EntityRecord {
  /** Schema version for this record shape. Must be "records/v2". */
  schema_version: "records/v2";
  /** Scoring formula version. Must be "v1.2" (compositeCore in scoring.ts/mjs). */
  methodology_version: "v1.2";

  // ── Identity (frozen from index JSON) ───────────────────────────────────────

  /**
   * URL-safe slug.  Identical to the slug logic in export-public-data.mjs:
   * explicit row.slug if present, else slugify(name), with -<rank> disambiguation
   * on intra-index collision. Must match badge/detail page URLs.
   */
  slug: string;
  name: string;
  /** One of the 8 canonical index slugs ("fortune-500", "countries", …). */
  index_slug: string;
  /** Entity kind matching export-public-data KIND_CONFIG (e.g. "company", "country"). */
  kind: string;

  // ── Published values (FROZEN, copied verbatim; never recomputed) ─────────────

  /**
   * == index.composite (G1: copied verbatim; migration performs no arithmetic).
   * 0–100 range, stored to 1 decimal place.
   */
  composite: number;
  /**
   * == index.band, normalised to Title Case
   * ("Critical"|"Developing"|"Functional"|"Established"|"Exemplary").
   */
  band: string;
  /** == index.rank within index_slug (G1: copied verbatim). */
  rank: number;
  /**
   * Set to the published composite when:
   *   (a) the entity name is in ASSESSOR_OVERRIDE_NAMES (validate-indexes.mjs), OR
   *   (b) |compositeCore(derivedDims).final − composite| > 1.0 (legacy rounding gap).
   * Null otherwise.
   *
   * Purpose: makes the record self-describing about any formula/published divergence.
   * ASSESSOR_OVERRIDE_NAMES remains the canonical allowlist; composite_override in the
   * record is a mirror for auditability only (ARCHITECTURE §9, check 16).
   */
  composite_override: number | null;

  // ── Derived dimensions (must equal index scores) ─────────────────────────────

  /**
   * round(mean(5 subdims), 2) for each dimension.
   * MUST equal index.scores[k] exactly (within 1e-9) — invariant G2.
   * For reconstructed dimensions all five subdims equal this value, so mean is exact.
   * For assessed dimensions the migration only accepts parsings that already satisfy G2.
   */
  dimensions: Record<DimensionCode, number>;

  // ── 40 subdimensions (CANONICAL scoring input) ──────────────────────────────

  /**
   * Exactly 40 entries in canonical order:
   *   AWR A1–A5, EMP E1–E5, ACT AC1–AC5, EQU EQ1–EQ5,
   *   BND B1–B5, ACC AB1–AB5, SYS S1–S5, INT I1–I5.
   * codes and names must match dimensions.ts verbatim.
   */
  subdimensions: SubdimensionRecord[];

  // ── Provenance ────────────────────────────────────────────────────────────────

  /**
   * Relative path from repo root to the source assessment file, e.g.
   * "research/assessments/hugging-face-2026-05-01.md". Null when no assessment
   * file was found or when all dimensions were reconstructed.
   */
  source_assessment: string | null;
  /**
   * Record-level roll-up.
   * 'assessed': at least one dimension used real subdim scores from an assessment.
   * 'reconstructed': all 40 subdims were reconstructed from published dimension values.
   */
  subdims_source: SubdimSource;
  /** ISO 8601 timestamp when this record was generated (generated_at of the run). */
  generated_at: string;
  /**
   * Generator identifier. Format: "build-entity-records.mjs@<git-sha>".
   * "unknown" when git sha cannot be determined.
   */
  generator: string;
}
